    AscendC::TQue<AscendC::TPosition::VECCALC, 1> accBuf_;
    AscendC::TQue<AscendC::TPosition::VECIN, 1> rowBuf_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

